const body    = $('Webhook - Receive Request').first().json.body;
const toolId  = (body.tool_id || '').trim();
const userId  = body.user_id;
const params  = body.params || {};

if (!toolId) {
  return [{ json: { user_id: userId, tool_id: toolId, params, entitled: false, credit_cost: 0, reason: 'missing_tool_id' } }];
}

const raw = $input.first().json;
const rows = Array.isArray(raw) ? raw : (raw ? [raw] : []);

let entitled  = false;
let creditCost = 1;
let reason    = 'tool_not_in_plan';

if (rows.length > 0) {
  const firstRow = rows[0];

  // Schema A: each row is { tool_id: string, enabled: bool, credit_cost: int }
  if (firstRow.tool_id !== undefined) {
    const entry = rows.find(r => r.tool_id === toolId);
    if (entry) {
      entitled   = entry.enabled === true;
      creditCost = entry.credit_cost || 1;
      reason     = entitled ? null : 'tool_not_in_plan';
    }
  }
  // Schema B: single row with boolean flag per tool_id and optional credit_costs JSONB
  else if (typeof firstRow[toolId] !== 'undefined') {
    entitled = firstRow[toolId] === true;
    const costs = firstRow.credit_costs || {};
    creditCost = (typeof costs === 'object' && costs[toolId]) ? costs[toolId] : 1;
    reason = entitled ? null : 'tool_not_in_plan';
  }
  // Schema C: single row with plan_features JSONB array
  else if (Array.isArray(firstRow.plan_features)) {
    entitled = firstRow.plan_features.includes(toolId);
    const costs = firstRow.credit_costs || {};
    creditCost = costs[toolId] || 1;
    reason = entitled ? null : 'tool_not_in_plan';
  }
}

return [{
  json: { user_id: userId, tool_id: toolId, params, entitled, credit_cost: creditCost, reason }
}];

const ctx    = $('Code - Check Tool Entitlement').first().json;
const credit = $input.first().json;  // credit deduction response

const toolId = ctx.tool_id;
const base   = $vars.GLOBAL_APP_URL_STG || 'https://stg.nova-ops.space';

// Lookup map: tool_id → Launchpad webhook URL
const toolMap = {
  lead_gen:            `${base}/api/webhooks/tools/lead-gen`,
  copywriting:         `${base}/api/webhooks/tools/copywriting`,
  offer_building:      `${base}/api/webhooks/tools/offer-building`,
  funnel_mapping:      `${base}/api/webhooks/tools/funnel-mapping`,
  content_calendar:    `${base}/api/webhooks/tools/content-calendar`,
  ad_strategy:         `${base}/api/webhooks/tools/ad-strategy`,
  email_sequence:      `${base}/api/webhooks/tools/email-sequence`,
  seo_brief:           `${base}/api/webhooks/tools/seo-brief`,
  competitor_research: `${base}/api/webhooks/tools/competitor-research`,
  social_planning:     `${base}/api/webhooks/tools/social-planning`,
  sales_script:        `${base}/api/webhooks/tools/sales-script`,
  brand_voice:         `${base}/api/webhooks/tools/brand-voice`,
  analytics:           `${base}/api/webhooks/tools/analytics`,
  automation_build:    `${base}/api/webhooks/tools/automation-build`,
  client_reporting:    `${base}/api/webhooks/tools/client-reporting`,
  general_question:    `${base}/api/webhooks/tools/general-question`
};

const toolUrl = toolMap[toolId];
if (!toolUrl) {
  throw new Error(`Unknown tool_id: '${toolId}'. Add it to the dispatch map.`);
}

return [{
  json: {
    tool_url:    toolUrl,
    tool_id:     toolId,
    user_id:     ctx.user_id,
    params:      ctx.params,
    credit_cost: ctx.credit_cost,
    credit_ok:   credit.allowed !== false
  }
}];
